mapper.select:
SELECT COUNT(*)
FROM qna q JOIN cs_category c ON q.cs_cate_no = c.cs_cate_no
WHERE c.parent_no = #{parentNo}

mapper.update:
UPDATE qna SET member_no=#{memberNo}, cs_cate_no=#{csCateNo}, title=#{title}, content=#{content}, answer=#{answer},
answer_member_no=#{answerMemberNo}, status=#{status}, answer_date=#{answerDate}
WHERE qna_no=#{qnaNo}
